content:
{
  "sentences": [
    {
      "text": "我們要約會，一起去喝咖啡好嗎？",
      "pinyin": "Wǒmen yào yuēhuì, yīqǐ qù hē kāfēi hǎo ma?",
      "pinyin_numeric": "wo3men yao4 yue1hui4, yi1qi3 qu4 he1 ka1fei1 hao3 ma0",
      "translation_en": "We are going on a date; shall we go drink coffee together?",
      "translation_ko": "우리는 데이트를 할 거예요. 같이 커피 마시러 갈까요?"
    },
    {
      "text": "他明天要見朋友，在咖啡店碰面。",
      "pinyin": "Tā míngtiān yào jiàn péngyou, zài kāfēidiàn pèngmiàn.",
      "pinyin_numeric": "ta1 ming2tian1 yao4 jian4 peng2you, zai4 ka1fei1dian4 peng4mian4",
      "translation_en": "He is going to meet a friend tomorrow; they will meet at the coffee shop.",
      "translation_ko": "그는 내일 친구를 만날 거예요. 커피숍에서 만나기로 했어요.",
      "note": "peng2you is a common variant; standard is peng2you3"
    },
    {
      "text": "我們要一起去吃飯，然後看電影。",
      "pinyin": "Wǒmen yào yīqǐ qù chīfàn, ránhòu kàn diànyǐng.",
      "pinyin_numeric": "wo3men yao4 yi1qi3 qu4 chi1fan4, ran2hou4 kan4 dian4ying3",
      "translation_en": "We are going to eat together and then watch a movie.",
      "translation_ko": "우리는 같이 밥을 먹고, 그다음에 영화를 볼 거예요."
    },
    {
      "text": "她今天下午要逛街，跟妹妹一起。",
      "pinyin": "Tā jīntiān xiàwǔ yào guàngjiē, gēn mèimei yīqǐ.",
      "pinyin_numeric": "ta1 jin1tian1 xia4wu3 yao4 guang4jie1, gen1 mei4mei yi1qi3",
      "translation_en": "She is going shopping this afternoon with her younger sister.",
      "translation_ko": "그녀는 오늘 오후에 여동생과 함께 쇼핑하러 갈 거예요."
    },
    {
      "text": "我們要約時間，在餐廳門口見面。",
      "pinyin": "Wǒmen yào yuē shíjiān, zài cāntīng ménkǒu jiànmiàn.",
      "pinyin_numeric": "wo3men yao4 yue1 shi2jian1, zai4 can1ting1 men2kou3 jian4mian4",
      "translation_en": "We are going to arrange a time and meet at the restaurant entrance.",
      "translation_ko": "우리는 시간을 약속하고 식당 입구에서 만날 거예요."
    },
    {
      "text": "他明天要提早到，因為要改時間。",
      "pinyin": "Tā míngtiān yào tízǎo dào, yīnwèi yào gǎi shíjiān.",
      "pinyin_numeric": "ta1 ming2tian1 yao4 ti2zao3 dao4, yin1wei4 yao4 gai3 shi2jian1",
      "translation_en": "He is going to arrive early tomorrow because he needs to change the time.",
      "translation_ko": "그는 내일 일찍 도착할 거예요. 시간을 변경해야 하거든요."
    },
    {
      "text": "我們要取消約會，因為他最近很忙。",
      "pinyin": "Wǒmen yào qǔxiāo yuēhuì, yīnwèi tā zuìjìn hěn máng.",
      "pinyin_numeric": "wo3men yao4 qu3xiao1 yue1hui4, yin1wei4 ta1 zui4jin4 hen3 mang2",
      "translation_en": "We are going to cancel the date because he has been very busy lately.",
      "translation_ko": "우리는 데이트를 취소할 거예요. 그가 요즘 너무 바쁘거든요."
    },
    {
      "text": "她下個星期要見朋友，在電影院碰面。",
      "pinyin": "Tā xià ge xīngqī yào jiàn péngyou, zài diànyǐngyuàn pèngmiàn.",
      "pinyin_numeric": "ta1 xia4 ge4 xing1qi1 yao4 jian4 peng2you, zai4 dian4ying3yuan4 peng4mian4",
      "translation_en": "She is going to meet a friend next week; they will meet at the movie theater.",
      "translation_ko": "그녀는 다음 주에 친구를 만날 거예요. 영화관에서 만나기로 했어요."
    },
    {
      "text": "我們要一起去聊天，在咖啡店喝咖啡。",
      "pinyin": "Wǒmen yào yīqǐ qù liáotiān, zài kāfēidiàn hē kāfēi.",
      "pinyin_numeric": "wo3men yao4 yi1qi3 qu4 liao2tian1, zai4 ka1fei1dian4 he1 ka1fei1",
      "translation_en": "We are going to chat together and drink coffee at the coffee shop.",
      "translation_ko": "우리는 같이 수다를 떨고 커피숍에서 커피를 마실 거예요."
    },
    {
      "text": "他今天要遲到，因為要延後約會。",
      "pinyin": "Tā jīntiān yào chídào, yīnwèi yào yánhòu yuēhuì.",
      "pinyin_numeric": "ta1 jin1tian1 yao4 chi2dao4, yin1wei4 yao4 yan2hou4 yue1hui4",
      "translation_en": "He is going to be late today because he needs to postpone the date.",
      "translation_ko": "그는 오늘 늦을 거예요. 데이트를 연기해야 하거든요."
    }
  ]
}
